      request.open('GET', 'config.json', false);
      try {
        request.send(null);
        window.CONFIG = JSON.parse(request.responseText);
      } catch (e) {
        window.CONFIG = {
          SSL_GATEWAY: false,
          IS_BS: false,
          serverConfig: {
            mode: 1,
            ip: '127.0.0.1',
            port: 8686,
            timeout: 0,
            pathname: '/',
          },
          errorTips: true,
          https: false,
          deployEnable: false,
          gatewayPort: 8686,
          jsEnginePort: 8699,
          isShowGraphEntity: false,
          chunkSize: 2097152,
          isNotLogoutOnClose: false,
          isOem: false,
          oemWelcome: [],
          isShowImportExport: false,
          isResourceDelBtnShow: true,
          radio: 2,
        };
      }

      if (sessionStorage.getItem('IS_BS') !== null) {
        window.CONFIG.IS_BS = JSON.parse(sessionStorage.getItem('IS_BS'));
      } else {
        window.CONFIG.IS_BS = !window.require;
        sessionStorage.setItem('IS_BS', window.CONFIG.IS_BS);
      }

      if (parent !== window && parent.CONFIG && parent.CONFIG.serverConfig) {
        window.CONFIG.SSL_GATEWAY = parent.CONFIG.SSL_GATEWAY;
        window.CONFIG.IS_BS = parent.CONFIG.IS_BS;
        window.CONFIG.serverConfig.ip = parent.CONFIG.serverConfig.ip;
        window.CONFIG.serverConfig.port = parent.CONFIG.serverConfig.port;
        window.CONFIG.serverConfig.pathname = parent.CONFIG.serverConfig.pathname;
      } else {
        const pathName =
          location.pathname.slice(0, location.pathname.indexOf('desktop-frame')) || '/';
        window.CONFIG.serverConfig.pathname = sessionStorage.getItem('proxy_pathname') || pathName;

        if (!sessionStorage.getItem('proxy_pathname')) {
          sessionStorage.setItem('proxy_pathname', window.CONFIG.serverConfig.pathname);
        }

        if (window.CONFIG.IS_BS) {
          window.CONFIG.SSL_GATEWAY = location.protocol.includes('https');
          window.CONFIG.serverConfig.ip = location.hostname;
          window.CONFIG.serverConfig.port =
            +location.port || (window.CONFIG.SSL_GATEWAY ? 443 : 80);
        } else {
          sessionStorage.setItem('proxy_pathname', '/');
          window.CONFIG.serverConfig.pathname = '/';
        }
      }

